using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

var mlContext = new MLContext(seed: 42);

var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
IDataView dataView = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');

var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);

// Map "Yes"/"No" string to boolean using a serializable ValueMapping transform
var labelKeys = new[] { "Yes", "No" };
var labelValues = new[] { true, false };

var pipeline = mlContext.Transforms.Conversion.MapValue("Churned", labelKeys, labelValues, "ChurnedRaw")
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        "RegionEncoded",
        nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Churned",
        featureColumnName: "Features"));

var model = pipeline.Fit(split.TrainSet);

var testPredictions = model.Transform(split.TestSet);
try
{
    var metrics = mlContext.BinaryClassification.Evaluate(testPredictions, labelColumnName: "Churned");
    Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
}
catch (ArgumentOutOfRangeException)
{
    var trainPredictions = model.Transform(split.TrainSet);
    var metrics = mlContext.BinaryClassification.Evaluate(trainPredictions, labelColumnName: "Churned");
    Console.WriteLine($"Model trained (evaluated on training data — dataset too small for proper test split)");
    Console.WriteLine($"  AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
}

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>();
builder.Services.AddSingleton<ITransformer>(model);
builder.Services.AddSingleton(mlContext);
builder.Services.AddSingleton(sp =>
{
    var ctx = sp.GetRequiredService<MLContext>();
    var mdl = sp.GetRequiredService<ITransformer>();
    return ctx.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(mdl);
});

var app = builder.Build();

app.MapPost("/predict", (MLContext ctx, ITransformer mdl, CustomerData customer) =>
{
    var engine = ctx.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(mdl);
    var prediction = engine.Predict(customer);
    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Probability = prediction.Probability,
    });
});

app.Run();

public class CustomerData
{
    [LoadColumn(0)]
    public float Age { get; set; }

    [LoadColumn(1)]
    public float Income { get; set; }

    [LoadColumn(2)]
    public string Region { get; set; } = string.Empty;

    [LoadColumn(3)]
    public float PurchaseHistory { get; set; }

    [LoadColumn(4)]
    public string ChurnedRaw { get; set; } = string.Empty;
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }

    public float Probability { get; set; }

    public float Score { get; set; }
}

